const { ethers } = require("ethers");

// ABI fragments for ERC20 and DEX interactions
const ERC20_ABI = [
  "function name() view returns (string)",
  "function symbol() view returns (string)",
  "function decimals() view returns (uint8)",
  "function balanceOf(address owner) view returns (uint256)",
  "function allowance(address owner, address spender) view returns (uint256)",
  "function approve(address spender, uint256 amount) returns (bool)",
  "function transfer(address to, uint256 amount) returns (bool)",
  "event Approval(address indexed owner, address indexed spender, uint256 value)",
  "event Transfer(address indexed from, address indexed to, uint256 value)"
];

const DEX_ROUTER_ABI = [
  "function getAmountsOut(uint256 amountIn, address[] calldata path) view returns (uint256[] memory amounts)",
  "function swapExactTokensForTokens(uint256 amountIn, uint256 amountOutMin, address[] calldata path, address to, uint256 deadline) returns (uint256[] memory amounts)",
  "function swapExactETHForTokens(uint256 amountOutMin, address[] calldata path, address to, uint256 deadline) payable returns (uint256[] memory amounts)",
  "function swapExactTokensForETH(uint256 amountIn, uint256 amountOutMin, address[] calldata path, address to, uint256 deadline) returns (uint256[] memory amounts)",
  "function WETH() view returns (address)",
  "function factory() view returns (address)"
];

const DEX_FACTORY_ABI = [
  "function getPair(address tokenA, address tokenB) view returns (address pair)"
];

const PAIR_ABI = [
  "function getReserves() view returns (uint112 reserve0, uint112 reserve1, uint32 blockTimestampLast)",
  "function token0() view returns (address)",
  "function token1() view returns (address)"
];

class TokenSwapDApp {
  constructor(providerUrl, routerAddress, options = {}) {
    if (!providerUrl || typeof providerUrl !== "string") {
      throw new Error("Invalid provider URL");
    }
    if (!ethers.isAddress(routerAddress)) {
      throw new Error("Invalid router address");
    }

    this.provider = new ethers.JsonRpcProvider(providerUrl);
    this.routerAddress = ethers.getAddress(routerAddress);
    this.router = new ethers.Contract(this.routerAddress, DEX_ROUTER_ABI, this.provider);
    this.signer = null;
    this.userAddress = null;

    // Configurable slippage tolerance in basis points (default 0.5%)
    this.slippageBps = options.slippageBps || 50;
    // Configurable deadline in seconds (default 20 minutes)
    this.deadlineSeconds = options.deadlineSeconds || 1200;
    // Maximum slippage allowed: 50% (5000 bps) to prevent misconfiguration
    this.maxSlippageBps = 5000;
    // Minimum deadline: 30 seconds
    this.minDeadlineSeconds = 30;

    if (this.slippageBps < 1 || this.slippageBps > this.maxSlippageBps) {
      throw new Error(`Slippage must be between 1 and ${this.maxSlippageBps} basis points`);
    }
    if (this.deadlineSeconds < this.minDeadlineSeconds) {
      throw new Error(`Deadline must be at least ${this.minDeadlineSeconds} seconds`);
    }
  }

  async connectWallet(privateKey) {
    if (!privateKey || typeof privateKey !== "string") {
      throw new Error("Invalid private key");
    }

    try {
      this.signer = new ethers.Wallet(privateKey, this.provider);
      this.userAddress = await this.signer.getAddress();
      this.routerWithSigner = this.router.connect(this.signer);
      console.log(`Wallet connected: ${this.userAddress}`);
      return this.userAddress;
    } catch (error) {
      this.signer = null;
      this.userAddress = null;
      throw new Error(`Failed to connect wallet: ${error.message}`);
    }
  }

  async connectBrowserWallet() {
    if (typeof window === "undefined" || !window.ethereum) {
      throw new Error("No browser wallet detected");
    }

    try {
      const browserProvider = new ethers.BrowserProvider(window.ethereum);
      await browserProvider.send("eth_requestAccounts", []);
      this.signer = await browserProvider.getSigner();
      this.userAddress = await this.signer.getAddress();
      this.provider = browserProvider;
      this.router = new ethers.Contract(this.routerAddress, DEX_ROUTER_ABI, this.provider);
      this.routerWithSigner = this.router.connect(this.signer);
      console.log(`Browser wallet connected: ${this.userAddress}`);
      return this.userAddress;
    } catch (error) {
      this.signer = null;
      this.userAddress = null;
      throw new Error(`Failed to connect browser wallet: ${error.message}`);
    }
  }

  _ensureConnected() {
    if (!this.signer || !this.userAddress) {
      throw new Error("Wallet not connected. Call connectWallet() or connectBrowserWallet() first.");
    }
  }

  _validateAddress(address, label = "Address") {
    if (!address || !ethers.isAddress(address)) {
      throw new Error(`Invalid ${label}: ${address}`);
    }
    return ethers.getAddress(address);
  }

  _validateAmount(amount, label = "Amount") {
    if (amount === undefined || amount === null) {
      throw new Error(`${label} is required`);
    }
    const bn = ethers.toBigInt(amount);
    if (bn <= 0n) {
      throw new Error(`${label} must be greater than zero`);
    }
    return bn;
  }

  _getDeadline() {
    return Math.floor(Date.now() / 1000) + this.deadlineSeconds;
  }

  _calculateMinAmountOut(amountOut) {
    const amountBn = ethers.toBigInt(amountOut);
    const slippageMultiplier = 10000n - BigInt(this.slippageBps);
    return (amountBn * slippageMultiplier) / 10000n;
  }

  async getTokenInfo(tokenAddress) {
    tokenAddress = this._validateAddress(tokenAddress, "Token address");
    const token = new ethers.Contract(tokenAddress, ERC20_ABI, this.provider);

    try {
      const [name, symbol, decimals] = await Promise.all([
        token.name(),
        token.symbol(),
        token.decimals()
      ]);

      return {
        address: tokenAddress,
        name,
        symbol,
        decimals: Number(decimals)
      };
    } catch (error) {
      throw new Error(`Failed to fetch token info for ${tokenAddress}: ${error.message}`);
    }
  }

  async getBalance(tokenAddress) {
    this._ensureConnected();
    tokenAddress = this._validateAddress(tokenAddress, "Token address");

    const token = new ethers.Contract(tokenAddress, ERC20_ABI, this.provider);
    try {
      const balance = await token.balanceOf(this.userAddress);
      return balance;
    } catch (error) {
      throw new Error(`Failed to fetch balance: ${error.message}`);
    }
  }

  async getETHBalance() {
    this._ensureConnected();
    try {
      return await this.provider.getBalance(this.userAddress);
    } catch (error) {
      throw new Error(`Failed to fetch ETH balance: ${error.message}`);
    }
  }

  async getAllowance(tokenAddress) {
    this._ensureConnected();
    tokenAddress = this._validateAddress(tokenAddress, "Token address");

    const token = new ethers.Contract(tokenAddress, ERC20_ABI, this.provider);
    try {
      return await token.allowance(this.userAddress, this.routerAddress);
    } catch (error) {
      throw new Error(`Failed to fetch allowance: ${error.message}`);
    }
  }

  async approveToken(tokenAddress, amount = null) {
    this._ensureConnected();
    tokenAddress = this._validateAddress(tokenAddress, "Token address");

    // If no amount specified, approve the exact amount needed rather than max uint256
    // For convenience mode, users can explicitly pass ethers.MaxUint256
    const approvalAmount = amount !== null ? this._validateAmount(amount, "Approval amount") : ethers.MaxUint256;

    const token = new ethers.Contract(tokenAddress, ERC20_ABI, this.signer);

    try {
      // Check current allowance first to avoid unnecessary transactions
      const currentAllowance = await token.allowance(this.userAddress, this.routerAddress);
      if (currentAllowance >= approvalAmount) {
        console.log("Sufficient allowance already exists");
        return { alreadyApproved: true, allowance: currentAllowance };
      }

      // If there's an existing non-zero allowance, reset to 0 first (for tokens like USDT)
      if (currentAllowance > 0n) {
        console.log("Resetting allowance to 0 before setting new allowance...");
        const resetTx = await token.approve(this.routerAddress, 0);
        await resetTx.wait();
        console.log("Allowance reset to 0");
      }

      console.log(`Approving ${approvalAmount === ethers.MaxUint256 ? "unlimited" : approvalAmount.toString()} tokens...`);
      const tx = await token.approve(this.routerAddress, approvalAmount);
      console.log(`Approval transaction sent: ${tx.hash}`);

      const receipt = await tx.wait();
      if (receipt.status !== 1) {
        throw new Error("Approval transaction failed");
      }

      console.log(`Approval confirmed in block ${receipt.blockNumber}`);
      return {
        transactionHash: tx.hash,
        blockNumber: receipt.blockNumber,
        approvedAmount: approvalAmount
      };
    } catch (error) {
      throw new Error(`Approval failed: ${error.message}`);
    }
  }

  async approveExactAmount(tokenAddress, amount) {
    return this.approveToken(tokenAddress, amount);
  }

  async ensureAllowance(tokenAddress, requiredAmount) {
    this._ensureConnected();
    tokenAddress = this._validateAddress(tokenAddress, "Token address");
    requiredAmount = this._validateAmount(requiredAmount, "Required amount");

    const currentAllowance = await this.getAllowance(tokenAddress);

    if (currentAllowance >= requiredAmount) {
      console.log("Sufficient allowance exists");
      return { alreadyApproved: true, allowance: currentAllowance };
    }

    // Approve max uint256 for convenience (standard DEX pattern)
    console.log("Insufficient allowance, requesting approval...");
    return this.approveToken(tokenAddress, ethers.MaxUint256);
  }

  async getAmountOut(amountIn, path) {
    if (!Array.isArray(path) || path.length < 2) {
      throw new Error("Path must contain at least 2 token addresses");
    }

    amountIn = this._validateAmount(amountIn, "Amount in");
    const validatedPath = path.map((addr, i) => this._validateAddress(addr, `Path address ${i}`));

    try {
      const amounts = await this.router.getAmountsOut(amountIn, validatedPath);
      return {
        amountIn: amounts[0],
        amountOut: amounts[amounts.length - 1],
        amounts: amounts.map(a => a),
        minAmountOut: this._calculateMinAmountOut(amounts[amounts.length - 1]),
        slippageBps: this.slippageBps
      };
    } catch (error) {
      throw new Error(`Failed to get quote: ${error.message}`);
    }
  }

  async getPairReserves(tokenA, tokenB) {
    tokenA = this._validateAddress(tokenA, "Token A");
    tokenB = this._validateAddress(tokenB, "Token B");

    try {
      const factoryAddress = await this.router.factory();
      const factory = new ethers.Contract(factoryAddress, DEX_FACTORY_ABI, this.provider);
      const pairAddress = await factory.getPair(tokenA, tokenB);

      if (pairAddress === ethers.ZeroAddress) {
        throw new Error("Pair does not exist");
      }

      const pair = new ethers.Contract(pairAddress, PAIR_ABI, this.provider);
      const [reserves, token0] = await Promise.all([
        pair.getReserves(),
        pair.token0()
      ]);

      const isToken0 = ethers.getAddress(token0) === ethers.getAddress(tokenA);

      return {
        pairAddress,
        reserveA: isToken0 ? reserves[0] : reserves[1],
        reserveB: isToken0 ? reserves[1] : reserves[0],
        blockTimestamp: reserves[2]
      };
    } catch (error) {
      throw new Error(`Failed to get pair reserves: ${error.message}`);
    }
  }

  async swapExactTokensForTokens(amountIn, tokenIn, tokenOut, options = {}) {
    this._ensureConnected();
    tokenIn = this._validateAddress(tokenIn, "Token in");
    tokenOut = this._validateAddress(tokenOut, "Token out");
    amountIn = this._validateAmount(amountIn, "Amount in");

    if (tokenIn === tokenOut) {
      throw new Error("Cannot swap a token for itself");
    }

    // Check balance
    const balance = await this.getBalance(tokenIn);
    if (balance < amountIn) {
      throw new Error(`Insufficient balance. Have: ${balance.toString()}, Need: ${amountIn.toString()}`);
    }

    // Build path
    const path = options.path || [tokenIn, tokenOut];
    const validatedPath = path.map((addr, i) => this._validateAddress(addr, `Path address ${i}`));

    // Ensure allowance
    await this.ensureAllowance(tokenIn, amountIn);

    // Get expected output
    const quote = await this.getAmountOut(amountIn, validatedPath);
    const minAmountOut = options.minAmountOut
      ? this._validateAmount(options.minAmountOut, "Min amount out")
      : quote.minAmountOut;

    const deadline = this._getDeadline();
    const recipient = options.recipient
      ? this._validateAddress(options.recipient, "Recipient")
      : this.userAddress;

    console.log(`Swapping ${amountIn.toString()} tokens...`);
    console.log(`Expected output: ${quote.amountOut.toString()}`);
    console.log(`Minimum output (with ${this.slippageBps / 100}% slippage): ${minAmountOut.toString()}`);

    try {
      // Estimate gas first to catch potential reverts early
      const gasEstimate = await this.routerWithSigner.swapExactTokensForTokens.estimateGas(
        amountIn,
        minAmountOut,
        validatedPath,
        recipient,
        deadline
      );

      // Add 20% gas buffer
      const gasLimit = (gasEstimate * 120n) / 100n;

      const tx = await this.routerWithSigner.swapExactTokensForTokens(
        amountIn,
        minAmountOut,
        validatedPath,
        recipient,
        deadline,
        { gasLimit }
      );

      console.log(`Swap transaction sent: ${tx.hash}`);
      const receipt = await tx.wait();

      if (receipt.status !== 1) {
        throw new Error("Swap transaction failed");
      }

      console.log(`Swap confirmed in block ${receipt.blockNumber}`);

      return {
        transactionHash: tx.hash,
        blockNumber: receipt.blockNumber,
        amountIn: amountIn.toString(),
        expectedAmountOut: quote.amountOut.toString(),
        minAmountOut: minAmountOut.toString(),
        path: validatedPath,
        gasUsed: receipt.gasUsed.toString()
      };
    } catch (error) {
      if (error.message.includes("INSUFFICIENT_OUTPUT_AMOUNT")) {
        throw new Error("Swap failed: Output amount too low. Try increasing slippage tolerance.");
      }
      if (error.message.includes("EXPIRED")) {
        throw new Error("Swap failed: Transaction deadline expired.");
      }
      throw new Error(`Swap failed: ${error.message}`);
    }
  }

  async swapExactETHForTokens(amountInETH, tokenOut, options = {}) {
    this._ensureConnected();
    tokenOut = this._validateAddress(tokenOut, "Token out");

    const amountInWei = typeof amountInETH === "string" && amountInETH.includes(".")
      ? ethers.parseEther(amountInETH)
      : this._validateAmount(amountInETH, "Amount in ETH");

    // Check ETH balance
    const ethBalance = await this.getETHBalance();
    if (ethBalance < amountInWei) {
      throw new Error(`Insufficient ETH balance. Have: ${ethers.formatEther(ethBalance)}, Need: ${ethers.formatEther(amountInWei)}`);
    }

    const weth = await this.router.WETH();
    const path = options.path || [weth, tokenOut];
    const validatedPath = path.map((addr, i) => this._validateAddress(addr, `Path address ${i}`));

    const quote = await this.getAmountOut(amountInWei, validatedPath);
    const minAmountOut = options.minAmountOut
      ? this._validateAmount(options.minAmountOut, "Min amount out")
      : quote.minAmountOut;

    const deadline = this._getDeadline();
    const recipient = options.recipient
      ? this._validateAddress(options.recipient, "Recipient")
      : this.userAddress;

    console.log(`Swapping ${ethers.formatEther(amountInWei)} ETH for tokens...`);

    try {
      const gasEstimate = await this.routerWithSigner.swapExactETHForTokens.estimateGas(
        minAmountOut,
        validatedPath,
        recipient,
        deadline,
        { value: amountInWei }
      );

      const gasLimit = (gasEstimate * 120n) / 100n;

      const tx = await this.routerWithSigner.swapExactETHForTokens(
        minAmountOut,
        validatedPath,
        recipient,
        deadline,
        { value: amountInWei, gasLimit }
      );

      console.log(`Swap transaction sent: ${tx.hash}`);
      const receipt = await tx.wait();

      if (receipt.status !== 1) {
        throw new Error("Swap transaction failed");
      }

      return {
        transactionHash: tx.hash,
        blockNumber: receipt.blockNumber,
        amountInETH: ethers.formatEther(amountInWei),
        expectedAmountOut: quote.amountOut.toString(),
        minAmountOut: minAmountOut.toString(),
        path: validatedPath,
        gasUsed: receipt.gasUsed.toString()
      };
    } catch (error) {
      throw new Error(`ETH swap failed: ${error.message}`);
    }
  }

  async swapExactTokensForETH(amountIn, tokenIn, options = {}) {
    this._ensureConnected();
    tokenIn = this._validateAddress(tokenIn, "Token in");
    amountIn = this._validateAmount(amountIn, "Amount in");

    // Check balance
    const balance = await this.getBalance(tokenIn);
    if (balance < amountIn) {
      throw new Error(`Insufficient token balance. Have: ${balance.toString()}, Need: ${amountIn.toString()}`);
    }

    const weth = await this.router.WETH();
    const path = options.path || [tokenIn, weth];
    const validatedPath = path.map((addr, i) => this._validateAddress(addr, `Path address ${i}`));

    // Ensure allowance
    await this.ensureAllowance(tokenIn, amountIn);

    const quote = await this.getAmountOut(amountIn, validatedPath);
    const minAmountOut = options.minAmountOut
      ? this._validateAmount(options.minAmountOut, "Min amount out")
      : quote.minAmountOut;

    const deadline = this._getDeadline();
    const recipient = options.recipient
      ? this._validateAddress(options.recipient, "Recipient")
      : this.userAddress;

    console.log(`Swapping tokens for ETH...`);

    try {
      const gasEstimate = await this.routerWithSigner.swapExactTokensForETH.estimateGas(
        amountIn,
        minAmountOut,
        validatedPath,
        recipient,
        deadline
      );

      const gasLimit = (gasEstimate * 120n) / 100n;

      const tx = await this.routerWithSigner.swapExactTokensForETH(
        amountIn,
        minAmountOut,
        validatedPath,
        recipient,
        deadline,
        { gasLimit }
      );

      console.log(`Swap transaction sent: ${tx.hash}`);
      const receipt = await tx.wait();

      if (receipt.status !== 1) {
        throw new Error("Swap transaction failed");
      }

      return {
        transactionHash: tx.hash,
        blockNumber: receipt.blockNumber,
        amountIn: amountIn.toString(),
        expectedETHOut: ethers.formatEther(quote.amountOut),
        minETHOut: ethers.formatEther(minAmountOut),
        path: validatedPath,
        gasUsed: receipt.gasUsed.toString()
      };
    } catch (error) {
      throw new Error(`Token to ETH swap failed: ${error.message}`);
    }
  }

  async revokeApproval(tokenAddress) {
    this._ensureConnected();
    tokenAddress = this._validateAddress(tokenAddress, "Token address");

    const token = new ethers.Contract(tokenAddress, ERC20_ABI, this.signer);

    try {
      const currentAllowance = await token.allowance(this.userAddress, this.routerAddress);
      if (currentAllowance === 0n) {
        console.log("Allowance is already zero");
        return { alreadyRevoked: true };
      }

      const tx = await token.approve(this.routerAddress, 0);
      console.log(`Revoke transaction sent: ${tx.hash}`);
      const receipt = await tx.wait();

      if (receipt.status !== 1) {
        throw new Error("Revoke transaction failed");
      }

      console.log("Approval revoked successfully");
      return {
        transactionHash: tx.hash,
        blockNumber: receipt.blockNumber
      };
    } catch (error) {
      throw new Error(`Failed to revoke approval: ${error.message}`);
    }
  }

  setSlippage(bps) {
    if (typeof bps !== "number" || bps < 1 || bps > this.maxSlippageBps) {
      throw new Error(`Slippage must be between 1 and ${this.maxSlippageBps} basis points`);
    }
    this.slippageBps = Math.floor(bps);
    console.log(`Slippage set to ${this.slippageBps / 100}%`);
  }

  setDeadline(seconds) {
    if (typeof seconds !== "number" || seconds < this.minDeadlineSeconds) {
      throw new Error(`Deadline must be at least ${this.minDeadlineSeconds} seconds`);
    }
    this.deadlineSeconds = Math.floor(seconds);
    console.log(`Deadline set to ${this.deadlineSeconds} seconds`);
  }

  async getSwapPreview(amountIn, tokenIn, tokenOut, path = null) {
    tokenIn = this._validateAddress(tokenIn, "Token in");
    tokenOut = this._validateAddress(tokenOut, "Token out");
    amountIn = this._validateAmount(amountIn, "Amount in");

    const swapPath = path || [tokenIn, tokenOut];
    const validatedPath = swapPath.map((addr, i) => this._validateAddress(addr, `Path address ${i}`));

    const [quote, tokenInInfo, tokenOutInfo] = await Promise.all([
      this.getAmountOut(amountIn, validatedPath),
      this.getTokenInfo(tokenIn),
      this.getTokenInfo(tokenOut)
    ]);

    const amountInFormatted = ethers.formatUnits(amountIn, tokenInInfo.decimals);
    const amountOutFormatted = ethers.formatUnits(quote.amountOut, tokenOutInfo.decimals);
    const minAmountOutFormatted = ethers.formatUnits(quote.minAmountOut, tokenOutInfo.decimals);

    const price = parseFloat(amountOutFormatted) / parseFloat(amountInFormatted);

    return {
      tokenIn: tokenInInfo,
      tokenOut: tokenOutInfo,
      amountIn: amountIn.toString(),
      amountInFormatted,
      expectedAmountOut: quote.amountOut.toString(),
      expectedAmountOutFormatted: amountOutFormatted,
      minAmountOut: quote.minAmountOut.toString(),
      minAmountOutFormatted,
      price: price.toFixed(8),
      slippageBps: this.slippageBps,
      slippagePercent: `${this.slippageBps / 100}%`,
      path: validatedPath
    };
  }
}

